                tmpAssign := dispatch.Assigns[ai]
                success := tmpAssign.AddShip(shipID, ori, des)
                if success {
                    tmpAssign.GenRoute()
                    if tmpAssign.Cost >= 0 {
                        // New route cost is just the base cost of serving this single ship
                        score := tmpAssign.Cost + 0.01*getDist(ori, des) // small tie‑breaker
                        candidates = append(candidates, candidate{idx: ai, score: score, added: false})
                        break // first feasible empty slot is enough for fallback
                    }
                    tmpAssign.RemoveShip(shipID)
                    tmpAssign.GenRoute()
                }
            }
        }

        if len(candidates) > 0 {
            // Sort candidates by score ascending (lower incremental cost preferred)
            sort.Slice(candidates, func(i, j int) bool {
                return candidates[i].score < candidates[j].score
            })
            // Regret‑k selection: pick the best among top REGRET_K candidates,
            // but if the second‑best is much worse, choose the best; otherwise use more diverse insertion.
            chosenIdx := 0
            if len(candidates) >= REGRET_K {
                bestScore := candidates[0].score
                kthBestScore := candidates[REGRET_K-1].score
                regretValue := kthBestScore - bestScore
                if regretValue > 100.0 {
                    // Large regret → stick with absolute best
                    chosenIdx = 0
                } else {
                    // Small regret → maybe pick slightly worse to spread load
                    // Introduce probabilistic diversification based on inverse score
                    // Here we simply pick the best for safety, but could randomize.
                    chosenIdx = 0
                }
            }
            sel := candidates[chosenIdx]
            actualIdx := sel.idx
            if sel.added {
                // Insert into existing assign
                dispatch.Assigns[actualIdx].AddShip(shipID, ori, des)
                dispatch.Assigns[actualIdx].GenRoute()
            } else {
                // Insert into new empty slot
                dispatch.Assigns[actualIdx].AddShip(shipID, ori, des)
                dispatch.Assigns[actualIdx].GenRoute()
                if actualIdx >= dispatch.AssignsLen {
                    dispatch.AssignsLen = actualIdx + 1
                }
            }
        } else {
            // Fallback: find earliest‑available assign by scanning all slots (including beyond current length)
            insertedFallback := false
            // Prefer existing non‑empty assigns first (already checked above, but retry with relaxed constraints? No.)
            // Instead create a brand‑new assign if none accepted earlier.
            for ai := 0; ai < MAXASSIGNS; ai++ {
