                            dispatch.AssignsLen = ai + 1
                        }
                        insertedFallback = true
                        break
                    }
                    tmpAssign.RemoveShip(shipID)
                    tmpAssign.GenRoute()
                }
            }
            // If still not inserted (should not happen per problem statement), skip but log nothing per requirements.
            _ = insertedFallback
        }
    }

    dispatch.RenewnTotalCost()
    return dispatch

